<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --bg: #0f172a;
    --panel: #1e293b;
    --panel-2: #334155;
    --card: #f8fafc;
    --card-shadow: rgba(0,0,0,0.35);
    --accent: #38bdf8;
    --text: #e2e8f0;
    --muted: #94a3b8;
  }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: linear-gradient(160deg, #0f172a, #111c33);
    color: var(--text);
    min-height: 100vh;
    padding: 32px 20px;
  }
  header.app-header {
    max-width: 1100px;
    margin: 0 auto 24px;
  }
  header.app-header h1 {
    font-size: 26px;
    font-weight: 700;
    letter-spacing: -0.5px;
  }
  header.app-header p {
    color: var(--muted);
    font-size: 14px;
    margin-top: 4px;
  }
  .toolbar {
    max-width: 1100px;
    margin: 0 auto 24px;
    display: flex;
    gap: 10px;
  }
  #new-card {
    flex: 1;
    padding: 12px 14px;
    border-radius: 10px;
    border: 1px solid var(--panel-2);
    background: var(--panel);
    color: var(--text);
    font-size: 15px;
    outline: none;
    transition: border-color .15s, box-shadow .15s;
  }
  #new-card:focus {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(56,189,248,0.2);
  }
  #add-card {
    padding: 12px 22px;
    border-radius: 10px;
    border: none;
    background: var(--accent);
    color: #06263a;
    font-size: 15px;
    font-weight: 600;
    cursor: pointer;
    transition: transform .1s, filter .15s;
  }
  #add-card:hover { filter: brightness(1.08); }
  #add-card:active { transform: translateY(1px); }

  .board {
    max-width: 1100px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 18px;
  }
  .column {
    background: var(--panel);
    border-radius: 14px;
    padding: 14px;
    display: flex;
    flex-direction: column;
    min-height: 300px;
    border: 1px solid rgba(255,255,255,0.04);
    transition: background .15s, box-shadow .15s;
  }
  .column.drag-over {
    background: #223049;
    box-shadow: inset 0 0 0 2px var(--accent);
  }
  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
    padding: 2px 4px;
  }
  .col-header h2 {
    font-size: 14px;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--muted);
    font-weight: 700;
  }
  .count {
    background: var(--panel-2);
    color: var(--text);
    font-size: 13px;
    font-weight: 600;
    min-width: 24px;
    text-align: center;
    padding: 2px 8px;
    border-radius: 20px;
  }
  .cards {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }
  .card {
    background: var(--card);
    color: #0f172a;
    border-radius: 10px;
    padding: 12px 14px;
    box-shadow: 0 2px 6px var(--card-shadow);
    cursor: grab;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    font-size: 15px;
    line-height: 1.35;
    word-break: break-word;
    transition: transform .08s, box-shadow .15s, opacity .15s;
  }
  .card:hover { box-shadow: 0 4px 12px var(--card-shadow); }
  .card.dragging { opacity: 0.5; }
  .card-title { flex: 1; }
  .card-del {
    border: none;
    background: transparent;
    color: #94a3b8;
    font-size: 18px;
    line-height: 1;
    cursor: pointer;
    padding: 0 2px;
    border-radius: 6px;
    transition: background .12s, color .12s;
  }
  .card-del:hover { background: #fee2e2; color: #dc2626; }
</style>
</head>
<body>
  <header class="app-header">
    <h1>Kanban Board</h1>
    <p>Drag cards between columns — your board is saved automatically.</p>
  </header>

  <div class="toolbar">
    <input id="new-card" type="text" placeholder="What needs doing?" autocomplete="off">
    <button id="add-card">Add Card</button>
  </div>

  <div class="board">
    <section class="column" id="col-todo" data-col="todo">
      <div class="col-header">
        <h2>To Do</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-doing" data-col="doing">
      <div class="col-header">
        <h2>Doing</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-done" data-col="done">
      <div class="col-header">
        <h2>Done</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
  </div>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "kanban.board.v1";
  var COLUMNS = ["todo", "doing", "done"];

  // state: array of { id, title, col }
  var state = load();
  var nextId = state.reduce(function (m, c) { return Math.max(m, c.id); }, 0) + 1;

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(function (c) {
        return c && typeof c.title === "string" && COLUMNS.indexOf(c.col) !== -1;
      }).map(function (c) {
        return { id: Number(c.id), title: c.title, col: c.col };
      });
    } catch (e) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* ignore quota errors */ }
  }

  function colContainer(col) {
    return document.querySelector("#col-" + col + " .cards");
  }

  function makeCardEl(card) {
    var el = document.createElement("div");
    el.className = "card";
    el.setAttribute("draggable", "true");
    el.dataset.id = card.id;

    var title = document.createElement("span");
    title.className = "card-title";
    title.textContent = card.title;

    var del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "\u00D7";

    el.appendChild(title);
    el.appendChild(del);

    del.addEventListener("click", function (e) {
      e.stopPropagation();
      deleteCard(card.id);
    });

    el.addEventListener("dragstart", function (e) {
      el.classList.add("dragging");
      e.dataTransfer.effectAllowed = "move";
      e.dataTransfer.setData("text/plain", String(card.id));
    });
    el.addEventListener("dragend", function () {
      el.classList.remove("dragging");
    });

    return el;
  }

  function render() {
    COLUMNS.forEach(function (col) {
      colContainer(col).innerHTML = "";
    });
    state.forEach(function (card) {
      colContainer(card.col).appendChild(makeCardEl(card));
    });
    updateCounts();
  }

  function updateCounts() {
    COLUMNS.forEach(function (col) {
      var n = state.filter(function (c) { return c.col === col; }).length;
      document.querySelector("#col-" + col + " .count").textContent = n;
    });
  }

  function addCard(title) {
    var t = title.trim();
    if (!t) return;
    state.push({ id: nextId++, title: t, col: "todo" });
    save();
    render();
  }

  function deleteCard(id) {
    state = state.filter(function (c) { return c.id !== id; });
    save();
    render();
  }

  function moveCard(id, col) {
    var card = state.filter(function (c) { return c.id === id; })[0];
    if (!card || card.col === col) return;
    card.col = col;
    save();
    render();
  }

  // --- Controls ---
  var input = document.getElementById("new-card");
  var addBtn = document.getElementById("add-card");

  addBtn.addEventListener("click", function () {
    addCard(input.value);
    input.value = "";
    input.focus();
  });
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") {
      addCard(input.value);
      input.value = "";
    }
  });

  // --- Drag & drop on columns ---
  COLUMNS.forEach(function (col) {
    var colEl = document.getElementById("col-" + col);

    colEl.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      colEl.classList.add("drag-over");
    });
    colEl.addEventListener("dragleave", function (e) {
      if (!colEl.contains(e.relatedTarget)) {
        colEl.classList.remove("drag-over");
      }
    });
    colEl.addEventListener("drop", function (e) {
      e.preventDefault();
      colEl.classList.remove("drag-over");
      var id = Number(e.dataTransfer.getData("text/plain"));
      if (!isNaN(id)) moveCard(id, col);
    });
  });

  render();
})();
</script>
</body>
</html>
